using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollmentRequests = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and language." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and human civilization." }
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 papers and holds three patents in neural network optimization.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. James Morton", Title = "Associate Professor", Bio = "Dr. Morton focuses on discrete mathematics and graph theory. He received the Distinguished Teaching Award in 2023.", Email = "j.morton@university.edu" },
            new() { Id = 3, Name = "Prof. Linda Garcia", Title = "Professor", Bio = "Prof. Garcia is a published novelist and literary critic specializing in contemporary American fiction.", Email = "l.garcia@university.edu" },
            new() { Id = 4, Name = "Dr. Robert Kim", Title = "Assistant Professor", Bio = "Dr. Kim researches quantum mechanics and particle physics. He previously worked at CERN on the Large Hadron Collider.", Email = "r.kim@university.edu" },
            new() { Id = 5, Name = "Dr. Maria Santos", Title = "Professor", Bio = "Dr. Santos is a historian specializing in medieval European history and the Renaissance period.", Email = "m.santos@university.edu" },
            new() { Id = 6, Name = "Dr. Alan Turing Jr.", Title = "Associate Professor", Bio = "Dr. Turing Jr. specializes in software engineering and distributed systems. He has 15 years of industry experience at major tech companies.", Email = "a.turing@university.edu" }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS101", Title = "Introduction to Programming", Description = "An introductory course covering fundamental programming concepts using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00-9:50 AM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = true },
            new() { Id = 2, Code = "CS201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:00-11:20 AM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = true },
            new() { Id = 3, Code = "CS301", Title = "Software Engineering", Description = "Principles and practices of software development including requirements analysis, design patterns, testing, and agile methodologies.", Credits = 3, Schedule = "Mon/Wed 2:00-3:20 PM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[5], IsFeatured = false },
            new() { Id = 4, Code = "MATH101", Title = "Calculus I", Description = "Introduction to differential calculus covering limits, derivatives, and applications of differentiation.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00-10:50 AM", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[1], IsFeatured = true },
            new() { Id = 5, Code = "MATH201", Title = "Linear Algebra", Description = "Study of vector spaces, matrices, linear transformations, eigenvalues, and applications.", Credits = 3, Schedule = "Tue/Thu 1:00-2:20 PM", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[1], IsFeatured = false },
            new() { Id = 6, Code = "ENG101", Title = "College Writing", Description = "Development of critical reading and academic writing skills. Focus on argumentation, research methods, and clear prose.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00-11:50 AM", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[2], IsFeatured = false },
            new() { Id = 7, Code = "ENG205", Title = "American Literature", Description = "Survey of American literature from the colonial period to the present, examining major authors and literary movements.", Credits = 3, Schedule = "Tue/Thu 3:00-4:20 PM", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[2], IsFeatured = true },
            new() { Id = 8, Code = "PHYS101", Title = "General Physics I", Description = "Introduction to mechanics, thermodynamics, and waves. Includes laboratory component.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00-1:50 PM + Lab Thu 2:00-4:50 PM", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[3], IsFeatured = false },
            new() { Id = 9, Code = "PHYS301", Title = "Quantum Mechanics", Description = "Introduction to quantum theory including wave-particle duality, Schrödinger equation, and quantum states.", Credits = 3, Schedule = "Tue/Thu 10:00-11:20 AM", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[3], IsFeatured = true },
            new() { Id = 10, Code = "HIST101", Title = "World History I", Description = "Survey of world history from ancient civilizations through the Middle Ages, examining political, social, and cultural developments.", Credits = 3, Schedule = "Mon/Wed/Fri 2:00-2:50 PM", DepartmentId = 5, Department = _departments[4], Instructor = _instructors[4], IsFeatured = false }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public void SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        _enrollmentRequests.Add(request);
    }
}

