@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="/courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search courses..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (courses.Any())
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.Department.Name</td>
                    <td>@course.Credits</td>
                    <td>@course.Schedule</td>
                    <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p class="text-muted">No courses found matching your criteria.</p>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        courses = CatalogService.GetCourses(Search, DepartmentId);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted</h4>
        <p>Your enrollment request has been submitted successfully. You will receive a confirmation via your university email.</p>
    </div>
    <a href="/courses" class="btn btn-primary">Back to Course Catalog</a>
}
else
{
    <p>Complete the form below to submit an enrollment request.</p>

    <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" class="form-control" id="studentName" name="StudentName"
                   value="@request.StudentName" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" class="form-control" id="studentId" name="StudentId"
                   value="@request.StudentId" required placeholder="e.g., STU-12345" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select class="form-select" id="courseId" name="CourseId" required>
                <option value="">-- Select a Course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(request.CourseId == course.Id)">@course.Code — @course.Title (@course.Credits credits)</option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
        <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
    </form>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }
    [SupplyParameterFromForm] private EnrollmentRequest request { get; set; } = new();

    private List<Course> courses = new();
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (CourseId.HasValue && request.CourseId == 0)
        {
            request.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        CatalogService.SubmitEnrollmentRequest(request);
        submitted = true;
    }
}

